      )}

      {/* Recommended Videos Section */}
      {recommendedVideos && recommendedVideos.length > 0 && (
        <section className="py-20 bg-gray-50 dark:bg-gray-900">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
